            SetUnderSymbol(new ReadOnlySpan<byte>(src, srcOffset, length));

        public int SetUnderSymbol(ReadOnlySpan<byte> src)
        {
            const int sizeOfLengthField = 2;
            int limit = _parentMessage.Limit;
            _parentMessage.Limit = limit + sizeOfLengthField + src.Length;
            _buffer.Uint16PutLittleEndian(limit, (ushort)src.Length);
            _buffer.SetBytes(limit + sizeOfLengthField, src);

            return src.Length;
        }

        public string GetUnderSymbol()
        {
            const int sizeOfLengthField = 2;
            int limit = _parentMessage.Limit;
            _buffer.CheckLimit(limit + sizeOfLengthField);
            int dataLength = (int)_buffer.Uint16GetLittleEndian(limit);
            _parentMessage.Limit = limit + sizeOfLengthField + dataLength;
            return _buffer.GetStringFromBytes(UnderSymbolResolvedCharacterEncoding, limit + sizeOfLengthField, dataLength);
        }

        public void SetUnderSymbol(string value)
        {
            var encoding = UnderSymbolResolvedCharacterEncoding;
            const int sizeOfLengthField = 2;
            int limit = _parentMessage.Limit;
            int byteCount = encoding.GetByteCount(value);

            _parentMessage.Limit = limit + sizeOfLengthField + byteCount;

            _buffer.SetBytesFromString(encoding, value, limit + sizeOfLengthField);
            _buffer.Uint16PutLittleEndian(limit, (ushort)byteCount);
        }

        public const int ExchangeId = 19;
        public const int ExchangeSinceVersion = 0;
        public const int ExchangeDeprecated = 0;
        public bool ExchangeInActingVersion()
        {
            return _actingVersion >= ExchangeSinceVersion;
        }

        public const int ExchangeOffset = -1;

        public const string ExchangeCharacterEncoding = "UTF-8";
        public static Encoding ExchangeResolvedCharacterEncoding = Encoding.GetEncoding(ExchangeCharacterEncoding);


        public static string ExchangeMetaAttribute(MetaAttribute metaAttribute)
        {
            switch (metaAttribute)
            {
                case MetaAttribute.Epoch: return "";
                case MetaAttribute.TimeUnit: return "";
                case MetaAttribute.SemanticType: return "";
                case MetaAttribute.Presence: return "required";
            }

            return "";
        }

        public const int ExchangeHeaderSize = 2;
        
        public int ExchangeLength()
        {
            _buffer.CheckLimit(_parentMessage.Limit + 2);
            return (int)_buffer.Uint16GetLittleEndian(_parentMessage.Limit);
        }

        public int GetExchange(byte[] dst, int dstOffset, int length) =>
            GetExchange(new Span<byte>(dst, dstOffset, length));

        public int GetExchange(Span<byte> dst)
        {
            const int sizeOfLengthField = 2;
            int limit = _parentMessage.Limit;
            _buffer.CheckLimit(limit + sizeOfLengthField);
            int dataLength = (int)_buffer.Uint16GetLittleEndian(limit);
            int bytesCopied = Math.Min(dst.Length, dataLength);
            _parentMessage.Limit = limit + sizeOfLengthField + dataLength;
            _buffer.GetBytes(limit + sizeOfLengthField, dst.Slice(0, bytesCopied));

            return bytesCopied;
        }
        
        // Allocates and returns a new byte array
        public byte[] GetExchangeBytes()
        {
            const int sizeOfLengthField = 2;
            int limit = _parentMessage.Limit;
            _buffer.CheckLimit(limit + sizeOfLengthField);
            int dataLength = (int)_buffer.Uint16GetLittleEndian(limit);
            byte[] data = new byte[dataLength];
            _parentMessage.Limit = limit + sizeOfLengthField + dataLength;
            _buffer.GetBytes(limit + sizeOfLengthField, data);

            return data;
        }

        public int SetExchange(byte[] src, int srcOffset, int length) =>
            SetExchange(new ReadOnlySpan<byte>(src, srcOffset, length));

        public int SetExchange(ReadOnlySpan<byte> src)
        {
            const int sizeOfLengthField = 2;
            int limit = _parentMessage.Limit;
            _parentMessage.Limit = limit + sizeOfLengthField + src.Length;
            _buffer.Uint16PutLittleEndian(limit, (ushort)src.Length);
            _buffer.SetBytes(limit + sizeOfLengthField, src);

            return src.Length;
        }

        public string GetExchange()
        {
            const int sizeOfLengthField = 2;
            int limit = _parentMessage.Limit;
            _buffer.CheckLimit(limit + sizeOfLengthField);
            int dataLength = (int)_buffer.Uint16GetLittleEndian(limit);
            _parentMessage.Limit = limit + sizeOfLengthField + dataLength;
            return _buffer.GetStringFromBytes(ExchangeResolvedCharacterEncoding, limit + sizeOfLengthField, dataLength);
        }

        public void SetExchange(string value)
        {
            var encoding = ExchangeResolvedCharacterEncoding;
            const int sizeOfLengthField = 2;
            int limit = _parentMessage.Limit;
            int byteCount = encoding.GetByteCount(value);

            _parentMessage.Limit = limit + sizeOfLengthField + byteCount;

            _buffer.SetBytesFromString(encoding, value, limit + sizeOfLengthField);
            _buffer.Uint16PutLittleEndian(limit, (ushort)byteCount);
        }

        public override string ToString()
        {
            var sb = new StringBuilder(100);
            var m = new TradeSlimMessage();
            m.WrapForDecode(_buffer, _offset, _actingBlockLength, _actingVersion);
            m.BuildString(sb);
            return sb.ToString();
        }

        internal void BuildString(StringBuilder builder)
        {
            if (_buffer == null)
            {
                throw new ArgumentNullException("_buffer");
            }

            int originalLimit = this.Limit;
            this.Limit = _offset + _actingBlockLength;
            builder.Append("[TradeSlimMessage](sbeTemplateId=");
            builder.Append(TradeSlimMessage.TemplateId);
            builder.Append("|sbeSchemaId=");
            builder.Append(TradeSlimMessage.SchemaId);
            builder.Append("|sbeSchemaVersion=");
            if (_parentMessage._actingVersion != TradeSlimMessage.SchemaVersion)
            {
                builder.Append(_parentMessage._actingVersion);
                builder.Append('/');
            }
            builder.Append(TradeSlimMessage.SchemaVersion);
            builder.Append("|sbeBlockLength=");
            if (_actingBlockLength != TradeSlimMessage.BlockLength)
            {
                builder.Append(_actingBlockLength);
                builder.Append('/');
            }
            builder.Append(TradeSlimMessage.BlockLength);
            builder.Append("):");

            builder.Append("UnsureSymbol=");
            builder.Append(this.UnsureSymbol);
            builder.Append('|');
            builder.Append("Condition=");
            builder.Append(this.Condition);
            builder.Append('|');
            builder.Append("LegCount=");
            builder.Append(this.LegCount);
            builder.Append('|');
            builder.Append("Quantity=");
            builder.Append(this.Quantity);
            builder.Append('|');
            builder.Append("BidSize=");
            builder.Append(this.BidSize);
            builder.Append('|');
            builder.Append("AskSize=");
            builder.Append(this.AskSize);
            builder.Append('|');
            builder.Append("Price=");
            builder.Append(this.Price);
            builder.Append('|');
            builder.Append("TradeDelta=");
            builder.Append(this.TradeDelta);
            builder.Append('|');
            builder.Append("Bid=");
            builder.Append(this.Bid);
            builder.Append('|');
            builder.Append("Ask=");
            builder.Append(this.Ask);
            builder.Append('|');
            builder.Append("UnderBid=");
            builder.Append(this.UnderBid);
            builder.Append('|');
            builder.Append("UnderAsk=");
            builder.Append(this.UnderAsk);
            builder.Append('|');
            builder.Append("DeltaAdjTheo=");
            builder.Append(this.DeltaAdjTheo);
            builder.Append('|');
            builder.Append("VolaDeltaAdjTheo=");
            builder.Append(this.VolaDeltaAdjTheo);
            builder.Append('|');
            builder.Append("ImpliedVol=");
            builder.Append(this.ImpliedVol);
            builder.Append('|');
            builder.Append("Vega=");
            builder.Append(this.Vega);
            builder.Append('|');
            builder.Append("TradeTime=");
            builder.Append(this.TradeTime);
            builder.Append('|');
            builder.Append("Symbol=");
            builder.Append('\'').Append(GetSymbol()).Append('\'');
            builder.Append('|');
            builder.Append("UnderSymbol=");
            builder.Append('\'').Append(GetUnderSymbol()).Append('\'');
            builder.Append('|');
            builder.Append("Exchange=");
            builder.Append('\'').Append(GetExchange()).Append('\'');

            this.Limit = originalLimit;

        }
    }
